def test_open_checking_account_one_below_minimum_boundary_rejected(verified_customer, api_client, notification_mock):
    payload = {"initial_deposit": 24, "currency": "USD"}
    resp = api_client.post("/accounts/checking", json=payload, headers=verified_customer["auth_headers"])
    assert resp.status_code == 422
    assert resp.json().get("error_code") == "DEPOSIT_BELOW_MINIMUM"
    assert notification_mock.event_count() == 0

